parameters.jsCode:
const response = $input.first().json;
const text = response.content[0].text.trim();
const prev = $('Build Prompt').first().json;

const subjectMatch = text.match(/^SUBJECT:\s*(.+?)(?=\nEMAIL:|$)/ms);
const emailMatch = text.match(/EMAIL:\s*(.+)$/ms);

const subject = subjectMatch ? subjectMatch[1].trim() : 'Following up on your inquiry';
const email_body = emailMatch ? emailMatch[1].trim() : text;

return [{
  json: {
    subject,
    email_body,
    lead_email: prev.lead_email,
    lead_name: prev.lead_name,
    lead_phone: prev.lead_phone,
    agent_name: prev.agent_name,
    agent_email: prev.agent_email,
    agent_phone: prev.agent_phone,
    brokerage: prev.brokerage,
    lead_id: prev.lead_id,
    client_id: prev.client_id,
    source: prev.source
  }
}];

